    private void btnBuscarActionPerformed(java.awt.event.ActionEvent evt) {//GEN-FIRST:event_btnBuscarActionPerformed
        ProductosControllers productosControllers = new ProductosControllers();
        DefaultTableModel modelo = (DefaultTableModel) JTableProductos.getModel();
        modelo.setRowCount(0);
        
        if(!txtCodigoBus.getText().isEmpty()){
            
         try {
            int codigoBuscar = Integer.parseInt(txtCodigoBus.getText());
            ProductosModels producto = productosControllers.BuscarProductosID(codigoBuscar);
            
           if(producto != null){
               modelo.addRow(new Object[]{
               
               producto.getCodigoPro(),
               producto.getNombrePro(),
               producto.getCategoriaPro(),
               producto.getPrecioPro(),
               producto.getCantidadStock() 
               });
            }else{
                System.out.println("Producto no encontrado");
                LimpiarDatos();
            }
         }catch (NumberFormatException e) {
                System.out.println("Ingrese un código válido");
         }
        }
        else if(!txtCateBus1.getText().isEmpty()){
            try{
                modelo.setRowCount(0); // limpia la tabla

                String cateBuscar = txtCateBus1.getText();

              if(!cateBuscar.isEmpty()){
                productosControllers.BuscarProductosCate(cateBuscar, modelo);
              }
               // Validación si en caso que no encuentra el producto
                    if(modelo.getRowCount() == 0){
                        System.out.println("No Existe! La categoria del producto.");
                    }
            }
            catch(Exception e){
                System.out.println("Categoría inválida");
            }
        }
        else if(!txtNombreBus.getText().isEmpty()){
            try{
                modelo.setRowCount(0); // limpia la tabla
                String nombreBus = txtNombreBus.getText();
                if(!nombreBus.isEmpty()){
                    productosControllers.BuscarProductosNombre(nombreBus, modelo);
                }
                    // Validación si en caso que no encuentra el producto
                    if(modelo.getRowCount() == 0){
                        System.out.println("No Existe! El nombre del producto.");
                    }
            }
            catch(Exception e){
                System.out.println("Nombre inválido!");
            }
        }
    }//GEN-LAST:event_btnBuscarActionPerformed

