    public void LimpiarDatos(){
        txtCodigoBus.setText("");
        txtCateBus1.setText("");
        txtNombreBus.setText("");
        DefaultTableModel modelo = (DefaultTableModel) JTableProductos.getModel();
        modelo.setRowCount(0);
    }
